import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  Wallet, ShoppingBag, CreditCard, 
  LayoutDashboard, Plus, TrendingUp, ChevronRight,
  User as UserIcon, Users
} from 'lucide-react';
import { Link } from 'react-router-dom';

const Menu = () => {
  const [resumo, setResumo] = useState({ total: 0, quantidade: 0, totalCartoes: 0 });
  const [gastosPorUsuario, setGastosPorUsuario] = useState([]);
  const [perfil, setPerfil] = useState({ nome: 'Usuário', tipo: 'comum' });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function buscarDados() {
      setLoading(true);
      const { data: { user } } = await supabase.auth.getUser();
      
      if (user) {
        // 1. Perfil do Usuário
        const { data: perfilData } = await supabase
          .from('profiles')
          .select('nome, tipo_usuario')
          .eq('id', user.id)
          .single();
        
        if (perfilData) {
          setPerfil({ nome: perfilData.nome.split(' ')[0], tipo: perfilData.tipo_usuario });
        }

        // 2. Data do Mês Atual para Filtro
        const agora = new Date();
        const inicioMes = new Date(agora.getFullYear(), agora.getMonth(), 1).toISOString();

        // 3. Busca Compras (Centralizado no user_id e profiles)
        let query = supabase
          .from('compras')
          .select(`
            valor_total,
            user_id,
            profiles (nome)
          `)
          .gte('data_compra', inicioMes.split('T')[0]); // Filtra pela data da compra, não da criação

        // Se for comum, filtra apenas os dele.
        if (perfilData?.tipo_usuario !== 'proprietario') {
          query = query.eq('user_id', user.id);
        }

        const { data: compras } = await query;

        // 4. Busca Cartões Ativos do usuário
        const { data: cartoes } = await supabase
          .from('cartoes')
          .select('id')
          .eq('user_id', user.id);

        if (compras) {
          // FILTRO IMPORTANTE: Apenas compras que possuem um perfil vinculado (user_id válido)
          const comprasValidas = compras.filter(item => item.profiles !== null);

          const totalGeral = comprasValidas.reduce((acc, item) => acc + parseFloat(item.valor_total), 0);
          
          // Agrupar por usuário (Lógica para o Proprietário)
          const agrupado = comprasValidas.reduce((acc, item) => {
            const nomeUser = item.profiles?.nome || 'Pendente';
            acc[nomeUser] = (acc[nomeUser] || 0) + parseFloat(item.valor_total);
            return acc;
          }, {});

          const listaAgrupada = Object.keys(agrupado).map(nome => ({
            nome,
            valor: agrupado[nome]
          }));

          setGastosPorUsuario(listaAgrupada);
          setResumo({ 
            total: totalGeral, 
            quantidade: comprasValidas.length,
            totalCartoes: cartoes ? cartoes.length : 0
          });
        }
      }
      setLoading(false);
    }
    buscarDados();
  }, []);

  const theme = {
    primary: '#4361ee',
    dark: '#0f172a',
    textMuted: '#64748b',
    surface: '#ffffff',
    accent: '#3f37c9'
  };

  // Se estiver carregando, mostra um estado neutro ou spinner (opcional)
  if (loading) return <div style={{ padding: '40px', textAlign: 'center', color: theme.primary }}>Carregando...</div>;

  return (
    <div className="fade-in" style={{ padding: '25px', maxWidth: '1200px', margin: '0 auto', paddingBottom: '100px' }}>
      
      <header style={{ marginBottom: '35px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div>
          <span style={{ color: theme.textMuted, fontSize: '0.8rem', fontWeight: 800, textTransform: 'uppercase', letterSpacing: '1.5px' }}>Visão Geral</span>
          <h1 style={{ fontSize: '2.2rem', margin: '5px 0 0 0', fontWeight: 900, color: theme.dark, letterSpacing: '-1px' }}>
            Olá, {perfil.nome} 👋
          </h1>
        </div>
        <div style={{ background: '#eef2ff', padding: '12px', borderRadius: '18px' }}>
          <TrendingUp color={theme.primary} size={28} />
        </div>
      </header>

      {/* CARD PRINCIPAL DINÂMICO */}
      <div style={mainCardStyle(theme)}>
        <div style={{ position: 'relative', zIndex: 2 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', opacity: 0.8, marginBottom: '15px' }}>
            {perfil.tipo === 'proprietario' ? <Users size={18} /> : <UserIcon size={18} />}
            <span style={{ fontSize: '0.95rem', fontWeight: 600 }}>
              {perfil.tipo === 'proprietario' ? 'Dívidas Totais do Mês' : 'Sua Dívida este Mês'}
            </span>
          </div>

          <div style={{ marginBottom: '30px' }}>
            <h2 style={{ fontSize: '3.2rem', margin: 0, fontWeight: 900, letterSpacing: '-2px' }}>
              R$ {resumo.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
            </h2>
          </div>

          {/* ÁREA DE MINI-CARDS (SÓ PARA PROPRIETÁRIO) */}
          {perfil.tipo === 'proprietario' && gastosPorUsuario.length > 0 && (
            <div style={miniCardsContainer}>
              {gastosPorUsuario.map((g, idx) => (
                <div key={idx} style={miniCardStyle}>
                  <span style={miniCardLabel}>{g.nome.split(' ')[0]}</span>
                  <span style={miniCardValue}>R$ {g.valor.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                </div>
              ))}
            </div>
          )}

          <div style={{ display: 'flex', gap: '15px', marginTop: '25px', borderTop: '1px solid rgba(255,255,255,0.1)', paddingTop: '20px' }}>
            <div style={pillStyle}>
              <span style={pillLabel}>Lançamentos</span>
              <span style={{ fontWeight: 800, fontSize: '1rem' }}>{resumo.quantidade}</span>
            </div>
            <div style={pillStyle}>
              <span style={pillLabel}>Meus Cartões</span>
              <span style={{ fontWeight: 800, fontSize: '1rem' }}>{resumo.totalCartoes}</span>
            </div>
          </div>
        </div>
        <div style={decorationStyle(theme)} />
      </div>

      {/* AÇÕES RÁPIDAS */}
      <h3 style={{ marginBottom: '20px', color: theme.dark, fontWeight: 800, fontSize: '1.3rem', letterSpacing: '-0.5px' }}>Ações Rápidas</h3>
      
      <div style={gridStyle}>
        <QuickActionLink to="/dashboard" icon={<LayoutDashboard size={26} />} label="Dashboard" sub="Análise" color={theme.primary} />
        <QuickActionLink to="/cartoes" icon={<CreditCard size={26} />} label="Cartões" sub="Limites" color="#7209b7" />
        <QuickActionLink to="/listagem" icon={<ShoppingBag size={26} />} label="Extrato" sub="Histórico" color="#00cc66" />
        <QuickActionLink to="/lancamento" icon={<Plus size={26} />} label="Novo" sub="Lançar" color="#fff" bg={theme.primary} isPrimary />
      </div>

      <Link to="/perfil" style={{ textDecoration: 'none' }}>
        <div style={footerActionStyle(theme)}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
            <div style={footerIconBox(theme)}>
              <UserIcon size={20} color={theme.primary} />
            </div>
            <div>
              <span style={{ display: 'block', fontSize: '0.95rem', fontWeight: 800, color: theme.dark }}>Configurações de Perfil</span>
              <span style={{ fontSize: '0.8rem', color: theme.textMuted }}>Gerenciar sua conta e acessos</span>
            </div>
          </div>
          <ChevronRight size={20} color={theme.textMuted} />
        </div>
      </Link>
    </div>
  );
};

// --- COMPONENTES AUXILIARES ---
const QuickActionLink = ({ to, icon, label, sub, color, bg = 'white', isPrimary = false }) => (
  <Link to={to} style={{ textDecoration: 'none' }}>
    <div style={{ 
      background: bg, 
      padding: '24px', 
      borderRadius: '28px', 
      display: 'flex', 
      flexDirection: 'column', 
      gap: '12px',
      boxShadow: isPrimary ? '0 15px 30px rgba(67, 97, 238, 0.3)' : '0 4px 15px rgba(0,0,0,0.04)',
      border: isPrimary ? 'none' : '1px solid #f1f5f9',
      transition: 'all 0.3s ease',
      height: '100%'
    }}
    onMouseEnter={(e) => {
        e.currentTarget.style.transform = 'translateY(-6px)';
        e.currentTarget.style.boxShadow = '0 20px 35px rgba(0,0,0,0.08)';
    }}
    onMouseLeave={(e) => {
        e.currentTarget.style.transform = 'translateY(0)';
        e.currentTarget.style.boxShadow = isPrimary ? '0 15px 30px rgba(67, 97, 238, 0.3)' : '0 4px 15px rgba(0,0,0,0.04)';
    }}
    >
      <div style={{ 
        color: color, 
        background: isPrimary ? 'rgba(255,255,255,0.2)' : `${color}15`, 
        width: '52px', height: '52px', borderRadius: '18px', 
        display: 'flex', alignItems: 'center', justifyContent: 'center' 
      }}>
        {icon}
      </div>
      <div>
        <span style={{ display: 'block', fontWeight: 800, fontSize: '1.1rem', color: isPrimary ? '#fff' : '#0f172a' }}>{label}</span>
        <span style={{ fontSize: '0.8rem', fontWeight: 600, color: isPrimary ? 'rgba(255,255,255,0.7)' : '#64748b' }}>{sub}</span>
      </div>
    </div>
  </Link>
);

// --- ESTILOS ---
const mainCardStyle = (theme) => ({
  background: `linear-gradient(135deg, ${theme.dark} 0%, ${theme.accent} 100%)`, 
  borderRadius: '35px', 
  padding: '40px', 
  color: 'white', 
  marginBottom: '35px',
  position: 'relative',
  overflow: 'hidden',
  boxShadow: '0 25px 50px -12px rgba(15, 23, 42, 0.4)'
});

const miniCardsContainer = { display: 'flex', flexWrap: 'wrap', gap: '10px', marginBottom: '10px' };
const miniCardStyle = { background: 'rgba(255,255,255,0.15)', backdropFilter: 'blur(10px)', padding: '12px 18px', borderRadius: '18px', display: 'flex', flexDirection: 'column', minWidth: '120px', border: '1px solid rgba(255,255,255,0.1)' };
const miniCardLabel = { fontSize: '0.7rem', fontWeight: 700, textTransform: 'uppercase', opacity: 0.8, letterSpacing: '0.5px' };
const miniCardValue = { fontSize: '1rem', fontWeight: 800 };

const pillStyle = { display: 'flex', alignItems: 'center', gap: '8px', background: 'rgba(255,255,255,0.08)', padding: '8px 16px', borderRadius: '12px' };
const pillLabel = { fontSize: '0.75rem', opacity: 0.7, fontWeight: 600 };
const decorationStyle = (theme) => ({ position: 'absolute', bottom: '-80px', right: '-40px', width: '250px', height: '250px', background: theme.primary, filter: 'blur(100px)', opacity: 0.4 });
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))', gap: '18px', marginBottom: '40px' };
const footerActionStyle = (theme) => ({ background: '#fff', padding: '22px', borderRadius: '28px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', border: '1px solid #f1f5f9', boxShadow: '0 4px 10px rgba(0,0,0,0.02)' });
const footerIconBox = (theme) => ({ background: '#f8fafc', padding: '12px', borderRadius: '14px', border: '1px solid #e2e8f0' });

export default Menu;
